1	# ===================================================================
2	# File: syn/scripts/dc_run.tcl
3	# NVDLA Open Source Project
4	# Reference synthesis methodology script for Design Compiler
5	#
6	# Copyright (c) 2016 – 2017 NVIDIA Corporation. Licensed under the
7	# NVDLA Open Hardware License; see the "LICENSE.txt" file that came
8	# with this distribution for more information.
9	# ===================================================================
10	
11	# =====================
12	# Setup variables/procs
13	# =====================
14	
15	set synMsgInfo "Info:"
16	set synMsgErr  "Error:"
17	set synMsgWarn "Warning:"
18	
19	
20	# PROC: setVar => Utility proc to set flow variables 
21	# Env vars get highest priority, followed by TCL vars, followed by default vars.
22	proc setVar {var {default ""}} {
23	    global $var
24	    global synMsgInfo synMsgWarn
25	    if {[info exists ::env($var)]} {
26	        set $var $::env($var)
27	        puts "$synMsgInfo Setting $var from env, value = [set $var]"
28	    } elseif {[info exists $var]} {
29	        set $var [set $var]
30	        puts "$synMsgInfo Setting $var to [set $var]"
31	    } else {
32	        set $var $default
33	        puts "${synMsgWarn} Setting $var to default value \"[set $var]\""
34	        return
35	    }
36	}
37	
38	# PROC: profileSystem => Print general machine information. 
39	proc profileSystem {} {
40	    global env tcl_platform synMsgInfo
41	
42	    puts "${synMsgInfo} date = [clock format [clock seconds] -format {%c}]"
43	    puts "${synMsgInfo} cwd = [pwd]"
44	    set myHost [info hostname]
45	    puts "${synMsgInfo} executing on $myHost"
46	    exec lsb_release -idrc
47	    exec lscpu
48	}
49	
50	# PROC: writeReports => Common reporting proc. 
51	proc writeReports {{prefix "default"}} {
52	    global synMsgInfo
53	    global REPORT_DIR MODULE
54	    set syn_report_max_paths               50
55	    set syn_report_nworst                  5
56	    set syn_report_simple                  0
57	    set path_graph_max_paths 10000
58	    set syn_report_flags   "-input_pins -nets"
59	    set timing_flags [concat -nosplit -nworst $syn_report_nworst -max_paths $syn_report_max_paths -significant_digits 4 -attribute]
60	    if { [shell_is_in_topographical_mode] } {
61	        set timing_flags [concat $timing_flags -nets -physical -trans -cap] 
62	    }
63	    if {[info exists syn_report_flags]} {
64	        set timing_flags [concat $timing_flags $syn_report_flags]
65	    }
66	
67	    set module_report ${REPORT_DIR}/${MODULE}.${prefix}.report
68	    suppress_message [list "TIM-175"]
69	    redirect -append $module_report { report_qor -significant_digits 4 }
70	    unsuppress_message [list "TIM-175"]
71	    redirect -append $module_report { eval { report_timing } $timing_flags }
72	    redirect -append $module_report { report_constraint -all -sig 4 -nosplit }
73	    if { [shell_is_in_topographical_mode] } {
74		    redirect -append $module_report { report_congestion }
75	    }
76	    redirect -append $module_report { report_resources -hierarchy }
77	    redirect -append $module_report { report_clock -nosplit }
78	    redirect -append $module_report { report_clock -skew -nosplit }
79	    redirect -append $module_report { eval report_power -nosplit }
80	    redirect -append $module_report { report_threshold_voltage_group }
81	    #redirect -append $module_report { nvSynGeneral::reportLibAttributes }
82	    redirect -append $module_report { report_design }
83	
84	}
85	
86	# =================
87	# ===== BEGIN =====
88	# =================
89	# Print some information on host OS and resources
90	profileSystem
91	
92	# Print env snapshot into the log
93	foreach key [array names env] {
94	    global synMsgInfo
95		puts "${synMsgInfo} (ENV) $key = $env($key)"
96	}
97	
98	# SYN_MODE: "wlm" (wireload model - DEFAULT) , "dcg" (physical, using -spg) or "de" (physical, using Design Explorer)
99	setVar SYN_MODE wlm
100	
101	# Name of top-level design
102	setVar MODULE
103	
104	# Directories
105	setVar CONS_DIR cons
106	setVar DB_DIR db
107	setVar LOG_DIR log
108	setVar REPORT_DIR report
109	setVar NET_DIR net
110	setVar FV_DIR fv
111	setVar MW_DIR mw
112	setVar DLIB_DIR design_lib
113	setVar DEF_DIR def
114	setVar SCRIPTS_DIR scripts
115	setVar SEARCH_PATH "."
116	setVar RTL_EXTENSIONS ".v .sv .gv"
117	
118	# Dont proceed if you cant find the scripts directory for app vars and other settings. 
119	if {![file exists $SCRIPTS_DIR]} {
120	   puts "${synMsgErr} Unable to proceed, please specify SCRITPS_DIR. "
121	   exit 1
122	}
123	
124	# Extensions
125	setVar DB_EXT ddc
126	setVar NET_EXT gv
127	setVar SDC_VER "1.7"
128	
129	# Library settings
130	setVar TARGET_LIB ""
131	setVar LINK_LIB ""
132	setVar MW_LIB ""
133	setVar TF_FILE
134	setVar TLUPLUS_FILE
135	setVar TLUPLUS_MAPPING_FILE
136	setVar DONT_USE_LIST ""
137	setVar MIN_ROUTING_LAYER ""
138	setVar MAX_ROUTING_LAYER ""
139	setVar CLOCK_GATING_CELL ""
140	setVar DONT_UNGROUP_LIST ""
141	setVar HORIZONTAL_LAYERS ""
142	setVar VERTICAL_LAYERS ""
143	
144	setVar QA_MODE ""
145	
146	if {[shell_is_in_exploration_mode]} {
147	    set de_log_html_filename ${LOG_DIR}/${MODULE}_de.html
148	}
149	
150	set_app_var link_path ${LINK_LIB}
151	set_app_var target_library ${TARGET_LIB}
152	set library_name [file rootname [file tail [lindex ${TARGET_LIB} 0]]]
153	
154	
155	# SVF, to guide Formality
156	set_svf ${FV_DIR}/${MODULE}/${MODULE}.svf
157	puts "${synMsgInfo} Setting SVF to  ${FV_DIR}/${MODULE}/${MODULE}.svf"
158	
159	
160	# Misc Synthesis recipe variables
161	setVar DC_NUM_CORES 1; # Assume calling scripts sets this up correctly
162	setVar TIGHTEN_CGE 1; # Choose whether or not to overconstrain CG enable paths. 
163	set suppress_errors "VER-130 UID-95"
164	
165	set_host_options -max_cores ${DC_NUM_CORES}
166	
167	# Set up some application vars
168	if {[file exists "${SCRIPTS_DIR}/dc_app_vars.tcl"]} {
169	    puts "${synMsgInfo} Sourcing ${SCRIPTS_DIR}/dc_app_vars.tcl"
170	    source -echo -verbose ${SCRIPTS_DIR}/dc_app_vars.tcl
171	}
172	
173	# Make DC-G use the track definitions and not fill in the gaps with more routing resource!
174	#set_route_zrt_common_options -track_auto_fill false
175	
176	# force all reporting into work directory  (issue NV_GR_GPMSD_pri_target)
177	define_design_lib WORK -path     ${DLIB_DIR}/${MODULE}/work
178	set alib_library_analysis_path   ${DLIB_DIR}/${MODULE}
179	
180	# Read logical/timing libs
181	puts "${synMsgInfo} Read library and create alib"
182	read_file -format db $target_library
183	
184	
185	# Search path
186	set_app_var search_path "${SEARCH_PATH}"
187	
188	######################
189	## Section : synthesis
190	#####################
191	setVar RTL_DEPS ""
192	set vcsOpt "{-f $RTL_DEPS}"
193	catch {eval {analyze -format sverilog -work WORK} -vcs $vcsOpt} analyzeStatus
194	if { $analyzeStatus != 1 } {
195	    puts "${synMsgErr} Analyze failed!  Aborting..."
196	    exit 1
197	}
198	
199	# Elaborate and switch design to current block.
200	elaborate ${MODULE}
201	current_design ${MODULE}
202	
203	
204	# Libraries for physical synthesis
205	# remove mw first
206	if {[shell_is_in_exploration_mode]} {
207	    if {[ file exists ${MW_DIR}/${MODULE}_de.mw]} {
208	        exec rm -rf ${MW_DIR}/${MODULE}_de.mw
209	    }
210	} else {
211		if {[ file exists ${MW_DIR}/${MODULE}_dcg.mw]} {
212	    	exec rm -rf ${MW_DIR}/${MODULE}_dcg.mw
213		}
214	}
215	if {[shell_is_in_topographical_mode]} {
216	 set mw_logic1_net "VDD"
217	 set mw_logic0_net "VSS"
218	}
219	
220	
221	set mw_reference_library [list]
222	if {[shell_is_in_topographical_mode]} {
223	    set mw_reference_library ${MW_LIB}
224		set_app_var mw_reference_library $mw_reference_library
225	    
226	    # Create milkyway design database for block
227	    extend_mw_layers
228		if {[shell_is_in_exploration_mode]} {
229	    	create_mw_lib -technology ${TF_FILE} -mw_reference_library $mw_reference_library -open ${MW_DIR}/${MODULE}_de.mw
230		} else {
231			create_mw_lib -technology ${TF_FILE} -mw_reference_library $mw_reference_library -open ${MW_DIR}/${MODULE}_dcg.mw
232		}
233	    # read technology files
234	    set_tlu_plus_files -max_tluplus ${TLUPLUS_FILE} -min_tluplus ${TLUPLUS_FILE} -tech2itf_map ${TLUPLUS_MAPPING_FILE}
235	    redirect -file ${REPORT_DIR}/itf_check.rpt { check_tlu_plus_files }
236		redirect -file ${REPORT_DIR}/lib_report.rpt { report_lib $library_name }
237	
238	    if { ${HORIZONTAL_LAYERS} != "" } {
239	        set_preferred_routing_direction -layers "$HORIZONTAL_LAYERS" -direction horizontal 
240	    }
241	    if { ${VERTICAL_LAYERS} != "" } {
242	        set_preferred_routing_direction -layers "$VERTICAL_LAYERS" -direction vertical 
243	    }
244	    
245	}
246	
247	
248	
249	
250	if ![ link ] {
251	    puts "${synMsgErr} Failed to link. Aborting..."
252	    exit 1
253	}
254	
255	if {$QA_MODE == "link_only"} {
256	    puts "${synMsgInfo} Design linked successfully. Exiting gracefully."
257	    exit 0
258	}
259	
260	puts "${synMsgInfo} Analyze alibs"
261	alib_analyze_libs
262	
263	# Write out a DDC at this point. 
264	write -f ddc -hier -o ${DB_DIR}/${MODULE}.elaborated.ddc
265	
266	# Set wireload model
267	setVar WIRELOAD_MODEL_NAME ""
268	setVar WIRELOAD_MODEL_FILE ""
269	if {![shell_is_in_topographical_mode] && ![shell_is_in_exploration_mode]} {
270	    if { $WIRELOAD_MODEL_FILE != "" } {
271	        update_lib $library_name $WIRELOAD_MODEL_FILE -no_warnings
272	        puts "${synMsgInfo} Reading in wireload model file $WIRELOAD_MODEL_FILE ..."
273	    }
274	    if { $WIRELOAD_MODEL_NAME != ""} {
275	        set_wire_load_model  -name $WIRELOAD_MODEL_NAME
276	        set_wire_load_mode   top
277	        puts "${synMsgInfo} Setting wireload model to $WIRELOAD_MODEL_NAME"
278	    }
279	}
280	
281	
282	# Set dont use on user cells
283	if {[info exists DONT_USE_LIST] && (${DONT_USE_LIST} != "")} {
284	    set list_du [list]
285		foreach tempCelltLib ${DONT_USE_LIST} {
286	        set detectLibCells [get_lib_cells -regexp -quiet ".*/${tempCelltLib}"]
287	        if { [sizeof_collection $detectLibCells] > 0 } {
288				foreach_in_collection cell $detectLibCells {
289	                lappend list_du [get_object_name $cell]
290		            puts "${synMsgInfo} Putting dont_use attributes on [get_object_name $cell]"
291	            }
292	        }
293	    }
294		set_dont_use $list_du
295	}
296	
297	# Connect const port to inv to avoid having shorted ports
298	set_fix_multiple_port_nets -all -buffer_constants [get_designs *] 
299	
300	
301	# Read in a floorplan/macro placement TCL , and set up min/max routing layers if specified
302	if {[shell_is_in_topographical_mode]} {
303	    if {[file exists "${DEF_DIR}/${MODULE}.def"]} {
304			puts "${synMsgInfo} Reading input floorplan file ${DEF_DIR}/${MODULE}.def"
305			extract_physical_constraints -verbose "${DEF_DIR}/${MODULE}.def"
306	        report_physical_constraints
307		} else {
308			puts "${synMsgWarn} No DEF file found. Continuing without defnining a floorplan."
309		}
310	    
311	    # source the macro placement file if it exists
312		if {[info exists CONS_DIR] && [file exists "${CONS_DIR}/${MODULE}.macroplacement.tcl"]} {
313			source -echo -verbose ${CONS_DIR}/${MODULE}.macroplacement.tcl
314		} else {
315			puts "${synMsgWarn} No macro placement file found. Continuing without defnining a floorplan."
316		}
317		
318	    if {[info exists MAX_ROUTING_LAYER] && ${MAX_ROUTING_LAYER} != "" && [info exists MIN_ROUTING_LAYER] && ${MIN_ROUTING_LAYER} != "" } {
319			puts "${synMsgInfo} Min/max routing layers specified - ${MIN_ROUTING_LAYER}/${MAX_ROUTING_LAYER}"
320			set_ignored_layers -min_routing_layer ${MIN_ROUTING_LAYER} -max_routing_layer ${MAX_ROUTING_LAYER}
321		}	
322	}
323	
324	# Clock gating command
325	set power_cg_auto_identify  true
326	#if {[info exiists CLOCK_GATING_CELL] && ${CLOCK_GATING_CELL} != ""} {
327	#    set_clock_gating_style -sequential_cell latch -positive_edge_logic integrated:${CLOCK_GATING_CELL} -max_fanout 1000000000 -minimum_bitwidth 4 -control_point before -control_signal scan_enable
328	#}
329	
330	
331	# Latest constraints file SDC/cons
332	# source SDC file
333	if  {[info exists CONS_DIR] && [file exists "${CONS_DIR}/${MODULE}.sdc"]} {
334	    puts "${synMsgInfo} Reading input SDC ${CONS_DIR}/${MODULE}.sdc using \"read_sdc\""
335		read_sdc "${CONS_DIR}/${MODULE}.sdc"
336	}
337	
338	if  {[info exists CONS_DIR] && [file exists "${CONS_DIR}/${MODULE}.tcl"]} {
339	    puts "${synMsgInfo} Reading additional (non-SDC) constraints from ${CONS_DIR}/${MODULE}.tcl using \"source\""
340		source -echo -verbose "${CONS_DIR}/${MODULE}.tcl"
341	} 
342	 
343	# Tighten synthesis constraints for enable signals to clock gates
344	setVar CGLUT_FILE ""
345	if {![shell_is_in_exploration_mode]} {
346	    if { ${TIGHTEN_CGE} == 1 && [file exists $CGLUT_FILE]  } {
347	        puts "${synMsgInfo} Start tighten_cg_enable_constraints"
348	        # Reset all the clock gate latency apply in sdc
349	        reset_clock_gate_latency
350	    	source $CGLUT_FILE
351	    	set i 1
352	    	set size [llength [array names timingDeltaTableForCgEnable]]
353	    	set end_1st [expr $size/2]
354	    	set start_2nd [expr $end_1st + 1]
355	    	foreach tableIndex [lsort -integer [array names timingDeltaTableForCgEnable]] {
356	            if { $i=="1" } {
357	    			set lat [expr 1.0 * $timingDeltaTableForCgEnable($tableIndex) / 1000.0]
358	    			set start 1
359	    		} elseif { $i < "$end_1st"} {
360	    			set end [expr $tableIndex -1]
361	    			set fanoutTable($i) "${start}-${end} -${lat}"
362	    			set start $tableIndex
363	    			set lat [expr 1.0 * $timingDeltaTableForCgEnable($tableIndex) / 1000.0]
364	    		} elseif {$i == "$end_1st"} {
365	    			set fanoutTable($i) "${start}-inf -${lat}"
366	    			set start $tableIndex
367	    			set lat [expr 1.0 * $timingDeltaTableForCgEnable($tableIndex) / 1000.0]
368	    		} elseif {$i == "$size"} {
369	    			set end [expr $tableIndex -1]
370	    			set fanoutTable2nd($i) "${start}-${end} -${lat}"
371	    			set start $tableIndex
372	    			set lat [expr 1.0 * $timingDeltaTableForCgEnable($tableIndex) / 1000.0]
373	    		} elseif {$i > "$end_1st"} {
374	    			set end [expr $tableIndex -1]
375	    			set fanoutTable2nd($i) "${start}-${end} -${lat}"
376	    			set start $tableIndex
377	    			set lat [expr 1.0 * $timingDeltaTableForCgEnable($tableIndex) / 1000.0]
378	    		}
379	    		incr i 
380	        }
381	    	set fanoutTable2nd($i) "${start}-inf -${lat}"
382	    	puts "set_clock_gate_latency -stage 0 -fanout_latency {1-inf 0} -overwrite"
383	    	set_clock_gate_latency -stage 0 -fanout_latency {1-inf 0} -overwrite
384	    	set i 0
385	    	foreach fanout_lat [lsort -integer [array names fanoutTable]] {
386	    		if {$i == "0"} {
387	    			set fanout_latency "$fanoutTable($fanout_lat)"
388	    			incr i
389	    		} else {
390	    			set fanout_latency "$fanout_latency, $fanoutTable($fanout_lat)"
391	    		}
392	    	}
393	    	set i 0
394	    	foreach fanout_lat [lsort -integer [array names fanoutTable2nd]] {
395	    		if {$i == "0"} {
396	    			set fanout_latency2nd "$fanoutTable2nd($fanout_lat)"
397	    			incr i
398	    		} else {
399	    			set fanout_latency2nd "$fanout_latency2nd, $fanoutTable2nd($fanout_lat)"
400	    		}
401	    	}
402	    	
403	    	puts "set_clock_gate_latency -stage 1 -fanout_latency {$fanout_latency} -overwrite"
404	    	set_clock_gate_latency -stage 1 -fanout_latency "$fanout_latency" -overwrite
405	    	puts "set_clock_gate_latency -stage 2 -fanout_latency {$fanout_latency2nd} -overwrite"
406	    	set_clock_gate_latency -stage 2 -fanout_latency "$fanout_latency2nd" -overwrite
407	    }
408	}
409	
410	
411	# Prevent ungrouping of specific hierarchies
412	if {[info exists DONT_UNGROUP_LIST] && ${DONT_UNGROUP_LIST} != ""} {
413	    set retVal {}
414	    foreach single_design $dont_ungroup_list {
415	        set gdCmd1 "get_designs \"$single_design\""
416	        set gdList1 [eval $gdCmd1]
417	        if { [sizeof_collection $gdList1] > 0 } {
418	            set retVal [add_to_collection $retVal $gdList1]
419	        }
420	        set gdCmd2 "get_designs \"*\" -filter \"((defined(@original_design_name) && @original_design_name=~${single_design}) || (defined(@hdl_template) && @hdl_template=~${single_design})) \""
421	        set gdList2 [eval $gdCmd2]
422	        if { [sizeof_collection $gdList2] > 0 } {
423	        	set retVal [add_to_collection $retVal $gdList2 -unique]
424	        }
425	    }
426	    foreach_in_collection local_design $retVal {
427	        puts "Setting ungroup and boundary_optimization to false for [get_object_name $local_design]"
428	        set_ungroup 			   [get_object_name $local_design] false
429	        set_boundary_optimization  [get_object_name $local_design] false
430	    }
431	    if { [sizeof_collection $retVal]} {
432	        if {[shell_is_in_topographical_mode] && ![shell_is_in_exploration_mode]} {
433	           puts " Also calling set_ahfs_options command to prevent certain forms of boundary optimization"
434	           set_ahfs_options -preserve_boundary_phase true -no_port_punching $retVal
435	       }
436	    }
437	}
438	
439	# Ungroup for area reduction
440	setVar AREA_RECOVERY 1
441	if {[info exists AREA_RECOVERY] && ${AREA_RECOVERY} == 1} {
442		set_cost_priority {max_design_rules}
443		set_max_area 0.0
444	}
445	
446	write -f ddc -hier -o ${DB_DIR}/${MODULE}.precompile.ddc
447	
448	
449	# Compile commands
450	set compile_command ""
451	if {[shell_is_in_topographical_mode] && ${SYN_MODE} == "dcg" && ![shell_is_in_exploration_mode]} {
452		set compile_command "compile_ultra -no_seq_output_inversion  -gate_clock -spg -scan"
453	} elseif {[shell_is_in_topographical_mode] && ![shell_is_in_exploration_mode]} {
454		set compile_command "compile_ultra -no_seq_output_inversion  -gate_clock -scan"
455	} elseif {[shell_is_in_exploration_mode]} {
456	    set compile_command "compile_exploration  -no_seq_output_inversion -gate_clock"
457	}  else {
458	    set compile_command "compile_ultra -no_seq_output_inversion -no_autoungroup -scan"
459	}
460	
461	puts "${synMsgInfo} Structuring from scratch with compile command: $compile_command"
462	eval $compile_command
463	
464	# Dump database and generate reports 
465	write -f ddc -hier -o ${DB_DIR}/${MODULE}.preincr.ddc
466	writeReports "preincr"
467	
468	setVar INCREMENTAL_RECOMPILE_COUNT 0
469	if {![shell_is_in_exploration_mode]} {
470	    set incr_recompile_command "${compile_command} -incremental" 
471	    for { set currentIncrRecompilePass 0 } { $currentIncrRecompilePass < $INCREMENTAL_RECOMPILE_COUNT  } { incr currentIncrRecompilePass } {
472	        puts "${synMsgInfo} Incrementally recompiling (PASS [expr $currentIncrRecompilePass + 1] ), with command: $incr_recompile_command"
473	        eval $incr_recompile_command
474	        
475	        # Dump database and generate reports 
476	        write -f ddc -hier -o ${DB_DIR}/${MODULE}.postincr.[expr $currentIncrRecompilePass + 1].ddc
477	        writeReports "postincr.[expr $currentIncrRecompilePass + 1]"
478	    }
479	} else {
480	    puts "${synMsgInfo} Incremental compiles are not supported in Design Explorer. Skipping" 
481	}
482	
483	# Run area recovery
484	if {![shell_is_in_exploration_mode]} {
485	    if {[info exists AREA_RECOVERY] && $AREA_RECOVERY ==1 } {
486		     ungroup -all -flatten  
487		     optimize_netlist -area
488	    }
489	}
490	
491	# Dump all design collaterals
492	write -f ddc -hier -o ${DB_DIR}/${MODULE}.ddc
493	write_sdc -nosplit ${NET_DIR}/${MODULE}.sdc 
494	write -format verilog -hierarchy -out ${NET_DIR}/${MODULE}.gv
495	# Invoking write_def commands requires a Design Compiler Graphical license or an IC Compiler
496	if {[shell_is_in_topographical_mode] && ($SYN_MODE == "dcg")} {
497		write_def -output ${NET_DIR}/${MODULE}.full.def -all_vias -routed_nets -vias -components -specialnets -pins -blockages
498	}
499	
500	# Generate final reports
501	writeReports "final"
502	redirect ${REPORT_DIR}/${MODULE}.check_design { check_design }
503	redirect ${REPORT_DIR}/${MODULE}.check_timing { check_timing }
504	
505	# Stop recording the SVF. 
506	set_svf -off
507	
508	# Print out summary of generated design collateral
509	puts "${synMsgInfo} GENERATED NETLIST: ${NET_DIR}/${MODULE}.gv"
510	puts "${synMsgInfo} GENERATED DEF:     ${NET_DIR}/${MODULE}.full.def"
511	puts "${synMsgInfo} GENERATED SDC:     ${NET_DIR}/${MODULE}.sdc"
512	puts "${synMsgInfo} GENERATED DDC:     ${DB_DIR}/${MODULE}.ddc"
513	puts "${synMsgInfo} GENERATED REPORTS: \n\t[join [glob "${REPORT_DIR}/*${MODULE}*"] "\n\t"]"
514	
515	
516	# Close the MW libs
517	if {[shell_is_in_topographical_mode]} {
518	    close_mw_lib 
519	}
520	
521	# finish
522	exit
523	
524

